var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"그 소문, 알고 계세요?","JPN":"あの噂を知っていますか？","ENG":"Have you heard the rumor?","TWN":"你聽說那個傳聞了嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"아카데미에는 벌써 몇 년째 아무도 이름을 모르는 학생이 있대요.","JPN":"アカデミーにはもう何年も前から誰も名前を知らない生徒がいるらしいです。","ENG":"There's a hidden student in the Academy, whose name nobody knows.","TWN":"說是學院裡有個來了好多年，但都沒人知道他的名字的神秘學生。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"30번이랑 32번 사이에 있는...... 출석번호 31번.","JPN":"30番と32番の間にいる……出席番号31番。","ENG":"Student Number Thirty-one, between Thirty and Thirty-two.","TWN":"學號應該是30號和32號之間的……31號。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"벌써 몇 년씩이나 지났는데도 그 정체를 아는 사람이 없는 번호예요.","JPN":"何年も経っているのに、その正体を誰も知らない番号です。","ENG":"The number has been occupied by someone for years, but no one knows who it is.","TWN":"已經過去好幾年了，還是沒人知道那個學號究竟是什麼人。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"사실, 그 사건들만 아니었어도 이런 괴담을 진지하게 믿는 사람은 없었겠지만......","JPN":"あの事件がなかったら、こんな怪談を本気で信じる人はいなかったと思いますが……","ENG":"Actually, no one would be taking it seriously, if it weren't for those strange events.","TWN":"事實上，如果沒有那些事情，應該也不會有人真的相信這種怪談……"},"stage":{"bg":"CLASS","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"문제는 체육대회가 있을 때마다 가끔 1등이나 2등이 비어 있었다는 사실!","JPN":"なんと、運動会が実施されるたびに偶に1位か2位が空いているのです！","ENG":"The problem is, sometimes when the Academy holds a Field Day, for some games, somebody takes first or second place, but nobody knows who!","TWN":"問題是每次運動會比賽時，第一名或第二名都是空的！"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"아무도 모르는 31번과...... 항상 한 명씩 사라지는 대회 수상자!","JPN":"誰も知らない31番と……いつも1人分足りない入賞者！","ENG":"Student Number Thirty-one, that no one knows about... and the missing Field Day winner.","TWN":"如同謎一般的31號……以及一路過關斬將的大賽優勝者！"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"어때요, 브라우니 선생님? 둘 사이에 뭔가 연관이 있는 거 같지 않으세요?","JPN":"どうですか、ブラウニー先生？　この2つの事象に関連性があると思いませんか？","ENG":"What do you say, Ms. Moore? Don't you think there's a connection between them?","TWN":"布朗尼老師，您怎麼看？您不覺得這二者之間有些什麼關係嗎？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"호오...... 실종된 적 없는 실종자라. 꽤 흥미로운 현상인걸?","JPN":"ふむふむ……失踪したことのない失踪者かー。なかなか興味深い話ね。","ENG":"Ooh... A missing person who never really went missing? What an interesting subject!","TWN":"呵呵……從未失蹤的失蹤者，好像有點意思。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"하지만 선생님이 여러 차례 경고했지?","JPN":"でも、先生が何度も言ったでしょう？","ENG":"But I've warned you several times.","TWN":"不過我應該警告過你很多次吧？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"초보자가 함부로 초자연현상을 파헤치려 하는 건 위험해.","JPN":"初心者がむやみに超常現象を探るのは危険です。","ENG":"It's too dangerous for beginners like you to dig into supernatural phenomena.","TWN":"新手擅自調查超自然現象是很危險的事情。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"아차하면 되려 당하는 수가 있거든.","JPN":"下手したら危険な目にあってしまうから。","ENG":"You're not prepared for these kinds of situations.","TWN":"稍有不慎就會陷入危險。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"하지만 이 소문 때문에 불안하다면서 운동회에 안 나가겠다는 친구들이 많아요.","JPN":"でも、この噂のせいで不安だからと運動会に参加しない子が多いんです。","ENG":"But many of my friends don't want to join the Field Day because of this rumor.","TWN":"不過，有很多學生因為這個傳聞，都不願意參加運動會了。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"엄청 열심히 준비했는데...... 이대로는 당일에 운동장이 텅텅 빌지도 몰라요.","JPN":"一生懸命準備したのに……このままじゃ当日グラウンドがガラ空きになってしまいます。","ENG":"We've put a lot into this occasion... What if no one shows up?","TWN":"我們花了那麼多心思準備……這樣下去，可能都沒人參加運動會了。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"흐음, 그거라면 걱정 마.","JPN":"なるほど、それなら心配しないで。","ENG":"Hmm, don't worry.","TWN":"呃嗯，那個你不用擔心。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"이 <color=#ffd34c>다이브의 정복자</color> 브라우니 선생님에겐 언제나 해결책이 있으니까.","JPN":"この<color=#ffd34c>ダイブの征服者</color>ブラウニー先生は常に解決策を用意してるんだから。","ENG":"I, Brownie Moore, <color=#ffd34c>Dive Conqueror</color>, have a solution. As always.","TWN":"因為我布朗尼<color=#ffd34c>躍入征服者</color>總有解決的辦法啊。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};